  1→#include "LFP2D/WorldMap/LFPWorldMapNode.h"
  2→#include "LFP2D/WorldMap/LFPWorldNodeDataAsset.h"
  3→#include "PaperSpriteComponent.h"
  4→
  5→ALFPWorldMapNode::ALFPWorldMapNode()
  6→{
  7→	PrimaryActorTick.bCanEverTick = false;
  8→
  9→	RootSceneComponent = CreateDefaultSubobject<USceneComponent>(TEXT("RootScene"));
 10→	SetRootComponent(RootSceneComponent);
 11→
 12→	NodeSpriteComponent = CreateDefaultSubobject<UPaperSpriteComponent>(TEXT("NodeSprite"));
 13→	NodeSpriteComponent->SetupAttachment(RootSceneComponent);
 14→	// 精灵默认在 XZ 平面（竖直），旋转使其平躺在 XY 平面（俯视角）
 15→	NodeSpriteComponent->SetRelativeRotation(FRotator(0.f, 90.f, -90.f));
 16→	NodeSpriteComponent->TranslucencySortPriority = 1;
 17→
 18→	HighlightSpriteComponent = CreateDefaultSubobject<UPaperSpriteComponent>(TEXT("HighlightSprite"));
 19→	HighlightSpriteComponent->SetupAttachment(RootSceneComponent);
 20→	// 高亮层在节点精灵下方（Z 略低）
 21→	HighlightSpriteComponent->SetRelativeLocation(FVector(0.f, 0.f, -1.f));
 22→	HighlightSpriteComponent->SetRelativeRotation(FRotator(0.f, 90.f, -90.f));
 23→	HighlightSpriteComponent->TranslucencySortPriority = 2;
 24→	HighlightSpriteComponent->SetVisibility(false);
 25→}
 26→
 27→void ALFPWorldMapNode::InitFromRowData(const FLFPWorldNodeRow& Row)
 28→{
 29→	NodeID = Row.NodeID;
 30→	NodeType = Row.NodeType;
 31→	BattleMapName = Row.BattleMapName;
 32→	StarRating = Row.StarRating;
 33→	bCanEscape = Row.bCanEscape;
 34→	BaseGoldReward = Row.BaseGoldReward;
 35→	BaseFoodReward = Row.BaseFoodReward;
 36→	EventID = Row.EventID;
 37→	PrerequisiteNodeIDs = Row.PrerequisiteNodeIDs;
 38→
 39→	SetActorLocation(FVector(Row.PosX, Row.PosY, 0.f));
 40→}
 41→
 42→FLFPWorldNodeRow ALFPWorldMapNode::ExportToRowData() const
 43→{
 44→	FLFPWorldNodeRow Row;
 45→	Row.NodeID = NodeID;
 46→	FVector Loc = GetActorLocation();
 47→	Row.PosX = Loc.X;
 48→	Row.PosY = Loc.Y;
 49→	Row.NodeType = NodeType;
 50→	Row.BattleMapName = BattleMapName;
 51→	Row.StarRating = StarRating;
 52→	Row.bCanEscape = bCanEscape;
 53→	Row.BaseGoldReward = BaseGoldReward;
 54→	Row.BaseFoodReward = BaseFoodReward;
 55→	Row.EventID = EventID;
 56→	Row.PrerequisiteNodeIDs = PrerequisiteNodeIDs;
 57→	return Row;
 58→}
 59→
 60→FVector2D ALFPWorldMapNode::GetPosition2D() const
 61→{
 62→	FVector Loc = GetActorLocation();
 63→	return FVector2D(Loc.X, Loc.Y);
 64→}
 65→
 66→void ALFPWorldMapNode::SetPosition2D(FVector2D NewPos)
 67→{
 68→	SetActorLocation(FVector(NewPos.X, NewPos.Y, 0.f));
 69→}
 70→
 71→void ALFPWorldMapNode::SetNodeVisualData(ULFPWorldNodeDataAsset* InData)
 72→{
 73→	NodeVisualData = InData;
 74→	UpdateVisualState();
 75→}
 76→
 77→void ALFPWorldMapNode::UpdateVisualState()
 78→{
 79→	if (!NodeVisualData || !NodeSpriteComponent) return;
 80→
 81→	// 未揭开 → 显示迷雾精灵（如果有）
 82→	if (!bIsRevealed && NodeVisualData->FogSprite)
 83→	{
 84→		NodeSpriteComponent->SetSprite(NodeVisualData->FogSprite);
 85→		return;
 86→	}
 87→
 88→	// 已触发 → 显示已触发精灵（如果有）
 89→	if (bHasBeenTriggered && NodeVisualData->TriggeredSprite)
 90→	{
 91→		NodeSpriteComponent->SetSprite(NodeVisualData->TriggeredSprite);
 92→		return;
 93→	}
 94→
 95→	// 默认精灵
 96→	NodeSpriteComponent->SetSprite(NodeVisualData->DefaultSprite);
 97→}
 98→
 99→void ALFPWorldMapNode::SetHighlighted(bool bHighlight)
100→{
101→	if (HighlightSpriteComponent)
102→	{
103→		HighlightSpriteComponent->SetVisibility(bHighlight);
104→	}
105→}
